(window.webpackJsonp=window.webpackJsonp||[]).push([[312],{593:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {number[]} distance\\n * @param {number} start\\n * @param {number} destination\\n * @return {number}\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> distanceBetweenBusStops = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">distance, start, destination</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> dis1=<span class=\\"hljs-number\\">0</span>,dis2=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> n=distance.length\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=start;;i++){\\n    <span class=\\"hljs-keyword\\">let</span> id=(i+n) % n\\n    <span class=\\"hljs-keyword\\">if</span>(id===destination)<span class=\\"hljs-keyword\\">break</span>\\n    dis1+=distance[id]\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=start<span class=\\"hljs-number\\">-1</span>;;i--){\\n   \\n    <span class=\\"hljs-keyword\\">let</span> id=(i+n) % n\\n    dis2+=distance[id]\\n    <span class=\\"hljs-keyword\\">if</span>(id===destination)<span class=\\"hljs-keyword\\">break</span>\\n  }  \\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.min(dis1,dis2)\\n};\\n</code></pre>\\n"],"titleSlug":"distance-between-bus-stops","hasThinking":false,"content":"<p>\u73af\u5f62\u516c\u4ea4\u8def\u7ebf\u4e0a\u6709&nbsp;<code>n</code>&nbsp;\u4e2a\u7ad9\uff0c\u6309\u6b21\u5e8f\u4ece&nbsp;<code>0</code>&nbsp;\u5230&nbsp;<code>n - 1</code>&nbsp;\u8fdb\u884c\u7f16\u53f7\u3002\u6211\u4eec\u5df2\u77e5\u6bcf\u4e00\u5bf9\u76f8\u90bb\u516c\u4ea4\u7ad9\u4e4b\u95f4\u7684\u8ddd\u79bb\uff0c<code>distance[i]</code>&nbsp;\u8868\u793a\u7f16\u53f7\u4e3a&nbsp;<code>i</code>&nbsp;\u7684\u8f66\u7ad9\u548c\u7f16\u53f7\u4e3a&nbsp;<code>(i + 1) % n</code>&nbsp;\u7684\u8f66\u7ad9\u4e4b\u95f4\u7684\u8ddd\u79bb\u3002</p>\\n\\n<p>\u73af\u7ebf\u4e0a\u7684\u516c\u4ea4\u8f66\u90fd\u53ef\u4ee5\u6309\u987a\u65f6\u9488\u548c\u9006\u65f6\u9488\u7684\u65b9\u5411\u884c\u9a76\u3002</p>\\n\\n<p>\u8fd4\u56de\u4e58\u5ba2\u4ece\u51fa\u53d1\u70b9&nbsp;<code>start</code>&nbsp;\u5230\u76ee\u7684\u5730&nbsp;<code>destination</code>&nbsp;\u4e4b\u95f4\u7684\u6700\u77ed\u8ddd\u79bb\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/09/08/untitled-diagram-1.jpg\\" style=\\"height: 240px; width: 388px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>distance = [1,2,3,4], start = 0, destination = 1\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u516c\u4ea4\u7ad9 0 \u548c 1 \u4e4b\u95f4\u7684\u8ddd\u79bb\u662f 1 \u6216 9\uff0c\u6700\u5c0f\u503c\u662f 1\u3002</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/09/08/untitled-diagram-1-1.jpg\\" style=\\"height: 240px; width: 388px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>distance = [1,2,3,4], start = 0, destination = 2\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u516c\u4ea4\u7ad9 0 \u548c 2 \u4e4b\u95f4\u7684\u8ddd\u79bb\u662f 3 \u6216 7\uff0c\u6700\u5c0f\u503c\u662f 3\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/09/08/untitled-diagram-1-2.jpg\\" style=\\"height: 240px; width: 388px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>distance = [1,2,3,4], start = 0, destination = 3\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u516c\u4ea4\u7ad9 0 \u548c 3 \u4e4b\u95f4\u7684\u8ddd\u79bb\u662f 6 \u6216 4\uff0c\u6700\u5c0f\u503c\u662f 4\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n&nbsp;&lt;= 10^4</code></li>\\n\\t<li><code>distance.length == n</code></li>\\n\\t<li><code>0 &lt;= start, destination &lt; n</code></li>\\n\\t<li><code>0 &lt;= distance[i] &lt;= 10^4</code></li>\\n</ul>\\n"}')}}]);